    10→import java.util.UUID;
    11→
    12→/**
    13→ * Incoming (primary) port that describes the use-cases the File Converter domain
    14→ * exposes to the outside world (e.g. REST controllers, GraphQL resolvers,
    15→ * asynchronous message listeners). <p>
    16→ *
    17→ * The interface is intentionally technology-agnostic and free of any framework
    18→ * dependencies so that the core domain remains portable and fully testable.
    19→ *
    20→ * Implementations live in the {@code application} layer and are wired to
    21→ * outbound ports (secondary adapters) that perform the actual I/O work, such as
    22→ * reading the source file from a blob store or delegating the conversion to an
    23→ * external SaaS.
    24→ */
    25→public interface FileConversionUseCase {
    26→
    27→    /**
    28→     * Creates a new conversion job. Depending on the implementation this call
    29→     * may be synchronous or queue an asynchronous background task.
    30→     *
    31→     * @param command immutable command that carries all data required to start
    32→     *                a conversion
    33→     * @return unique immutable {@link ConversionJobId}
    34→     * @throws UnsupportedFileFormatException when either source or target
    35→     *                                        format is not supported by the
    36→     *                                        current deployment
    37→     */
    38→    ConversionJobId submitConversion(ConvertFileCommand command)
    39→            throws UnsupportedFileFormatException;
    40→
    41→    /**
    42→     * Returns the current status of a conversion job.
    43→     *
    44→     * @param jobId unique job identifier as returned by
    45→     *              {@link #submitConversion(ConvertFileCommand)}
    46→     * @return {@link ConversionSnapshot} carrying status and additional metadata
    47→     * @throws JobNotFoundException when the job cannot be located
    48→     */
    49→    ConversionSnapshot queryStatus(ConversionJobId jobId) throws JobNotFoundException;
    50→
    51→    /**
    52→     * Retrieves the converted payload as a binary buffer <strong>if and only
    53→     * if</strong> the job has successfully completed. Implementations may
    54→     * decide to stream large files; this simplified interface suffices for most
    55→     * cases.
    56→     *
    57→     * @param jobId unique identifier of a completed job
    58→     * @return optional containing the payload or empty when the job is not yet
    59→     *         finished
    60→     * @throws JobNotFoundException               when the job cannot be located
    61→     * @throws ConversionFailedException          when the job finished in
    62→     *                                            {@link ConversionStatus#FAILED}
    63→     * @throws UnsupportedRetrievalStateException when the job is not in a state
    64→     *                                            that allows retrieval
    65→     */
    66→    Optional<ByteBuffer> fetchConvertedPayload(ConversionJobId jobId)
    67→            throws JobNotFoundException,
    68→                   ConversionFailedException,
    69→                   UnsupportedRetrievalStateException;
    70→
    71→    /**
    72→     * Attempts to cancel an in-flight conversion. A best-effort operation;
    73→     * implementations must guarantee idempotency.
    74→     *
    75→     * @param jobId job to cancel
    76→     * @throws JobNotFoundException            when the job cannot be located
    77→     * @throws ConversionAlreadyCompletedException when the job is already in a
    78→     *                                            terminal state
    79→     */
    80→    void cancelConversion(ConversionJobId jobId)
    81→            throws JobNotFoundException, ConversionAlreadyCompletedException;
    82→}
