    84→/* ========================================================================== */
    85→/* ===============================  Commands  =============================== */
    86→/* ========================================================================== */
    87→
    88→/**
    89→ * Immutable command object that starts a new conversion. Acts as the formal
    90→ * boundary between primary adapters and the application service.
    91→ */
    92→final class ConvertFileCommand {
    93→
    94→    private final Path sourcePath;
    95→    private final FileFormat sourceFormat;
    96→    private final FileFormat targetFormat;
    97→    private final Map<String, String> metadata; // arbitrary key-value data
    98→
    99→    private ConvertFileCommand(Builder builder) {
   100→        this.sourcePath   = builder.sourcePath;
   101→        this.sourceFormat = builder.sourceFormat;
   102→        this.targetFormat = builder.targetFormat;
   103→        this.metadata     = Collections.unmodifiableMap(builder.metadata);
   104→    }
   105→
   106→    public Path getSourcePath() {
   107→        return sourcePath;
   108→    }
   109→
   110→    public FileFormat getSourceFormat() {
   111→        return sourceFormat;
   112→    }
   113→
   114→    public FileFormat getTargetFormat() {
   115→        return targetFormat;
   116→    }
   117→
   118→    public Map<String, String> getMetadata() {
   119→        return metadata;
   120→    }
   121→
   122→    /* --------------------------  Builder pattern  -------------------------- */
   123→
   124→    public static Builder builder() {
   125→        return new Builder();
   126→    }
   127→
   128→    public static final class Builder {
   129→        private Path sourcePath;
   130→        private FileFormat sourceFormat;
   131→        private FileFormat targetFormat;
   132→        private Map<String, String> metadata = Collections.emptyMap();
   133→
   134→        private Builder() {
   135→        }
   136→
   137→        public Builder sourcePath(Path sourcePath) {
   138→            this.sourcePath = sourcePath;
   139→            return this;
   140→        }
   141→
   142→        public Builder sourceFormat(FileFormat sourceFormat) {
   143→            this.sourceFormat = sourceFormat;
   144→            return this;
   145→        }
   146→
