   175→
   176→    /**
   177→     * Thread-safe, TTL-aware in-memory registry. Could easily be swapped for
   178→     * Redis, DynamoDB, or Consul by implementing the same API.
   179→     */
   180→    @Component
   181→    static class ServiceRegistry {
   182→
   183→        /** Keyed by service instance ID */
   184→        private final Map<UUID, RegisteredService> store = new ConcurrentHashMap<>();
   185→
   186→        /* ---------------- Registration ---------------- */
   187→
   188→        public RegisteredService register(RegistrationRequest dto) {
   189→            UUID id  = UUID.randomUUID();
   190→            String host = resolveHost(dto.host());
   191→            RegisteredService service = new RegisteredService(
   192→                    id,
   193→                    dto.name(),
   194→                    host,
   195→                    dto.port(),
   196→                    dto.basePath(),
   197→                    Instant.now(),
   198→                    Duration.ofSeconds(dto.ttlSeconds())
   199→            );
   200→            store.put(id, service);
   201→            return service;
   202→        }
