   204→        /* ---------------- Deregistration -------------- */
   205→
   206→        @CacheEvict(value = "registryList", allEntries = true)
   207→        public void deregister(UUID id) {
   208→            RegisteredService removed = store.remove(id);
   209→            if (removed == null) {
   210→                throw new ServiceNotFoundException("No service registered with id " + id);
   211→            }
   212→        }
   213→
   214→        /* ---------------- Queries --------------------- */
   215→
   216→        @Cacheable("registryList")
   217→        public List<RegisteredService> list(Optional<String> serviceName) {
   218→            Stream<RegisteredService> stream = store.values().stream().filter(s -> !s.isExpired());
   219→            if (serviceName.isPresent()) {
   220→                stream = stream.filter(s -> s.name().equalsIgnoreCase(serviceName.get()));
   221→            }
   222→            return stream.sorted(Comparator.comparing(RegisteredService::registeredAt).reversed())
   223→                         .collect(Collectors.toList());
   224→        }
