    48→@SpringBootApplication
    49→@EnableConfigServer
    50→public class ConfigServerApplication {
    51→
    52→    private static final Logger LOG = LoggerFactory.getLogger(ConfigServerApplication.class);
    53→
    54→    public static void main(String[] args) {
