   109→     * Custom health indicator that surfaces repository availability and freshness. It delegates
   110→     * to Spring Cloud Config’s {@code EnvironmentRepository} rather than performing its own low-level
   111→     * Git or Vault checks, reducing coupling with the underlying storage technology.
   112→     */
   113→    @Bean
   114→    public HealthContributor repositoryHealthIndicator(AuditingEnvironmentRepository repo) {
   115→        return (HealthIndicator) () -> {
   116→            Duration age = repo.ageOfLastSuccess();
   117→            Health.Builder builder = repo.lastFetchSuccessful()
   118→                    ? Health.up()
   119→                    : Health.down();
   120→
   121→            return builder
   122→                    .withDetail("repository", repo.getDelegate().getClass().getSimpleName())
   123→                    .withDetail("lastFetchAge", age.toMillis() + "ms")
   124→                    .withDetail("lastFetchSuccessful", repo.lastFetchSuccessful())
   125→                    .build();
   126→        };
   127→    }
   128→
   129→    /**
   130→     * Emits an application-ready log entry that includes the active Spring profiles. This is
   131→     * convenient for DevOps teams performing zero-downtime rollouts, as they can verify that
   132→     * the profile combination matches expectation without scraping the entire application log.
   133→     */
   134→    @Bean
   135→    public ApplicationListener<ApplicationReadyEvent> logProfilesOnStartup(ConfigurableEnvironment env) {
