   148→    /**
   149→     * Wrapper that records whether the last fetch was successful and when it happened.
   150→     */
   151→    static final class AuditingEnvironmentRepository implements EnvironmentRepository {
   152→
   153→        private final EnvironmentRepository delegate;
   154→
   155→        private final AtomicReference<Long> lastSuccessEpochMilli = new AtomicReference<>(0L);
   156→        private final AtomicReference<Boolean> lastSuccess = new AtomicReference<>(false);
   157→
   158→        AuditingEnvironmentRepository(EnvironmentRepository delegate) {
   159→            this.delegate = delegate;
   160→        }
   161→
   162→        @Override
   163→        public Environment findOne(String application, String profile, String label) {
   164→            try {
   165→                Environment env = delegate.findOne(application, profile, label);
   166→                markSuccess();
   167→                return env;
   168→            } catch (RuntimeException ex) {
   169→                markFailure(ex);
   170→                throw ex;
   171→            }
   172→        }
   173→
   174→        void markSuccess() {
   175→            lastSuccess.set(true);
   176→            lastSuccessEpochMilli.set(System.currentTimeMillis());
   177→        }
   178→
   179→        void markFailure(Throwable t) {
